import styleButtonBlock from "./ButtonBlock.module.scss";
import React from "react";
import { useSelector, useDispatch } from "react-redux";
import { useHTTP } from "./../../../.././hook/http";

const ButtonBlock = (props) => {
  const { request } = useHTTP();
  const state = useSelector((state) => state.register);
  const dispatch = useDispatch();

  const toButton = async () => {
    const { nickName, email, password } = state;
    if (nickName === "" || email === "" || password === "") {
      return props.set("Поля должны быть заполнены");
    }

    const data = {
      nickName: nickName,
      email: email,
      password: password,
    };
    try {
      const response = await request(
        "http://localhost:5000/api/auth",
        "POST",
        JSON.stringify(data),
        { "Content-Type": "application/json" }
      );
      props.set(response.message.errors[0]["msg"]);
    } catch (error) {
      console.log(error);
    }
    dispatch(props.registerActin());
  };

  const toLogin = async () => {
    const { nickName, email, password } = state;
    if (email === "" || password === "") {
      return props.set("email и password обязательны для заполнения");
    }

    const data = {
      nickName: nickName,
      email: email,
      password: password,
    };
    try {
      const response = await request(
        "http://localhost:5000/api/login",
        "POST",
        JSON.stringify(data),
        { "Content-Type": "application/json" }
      );
      if (response.message === undefined) {
        props.set("Операция прошла успешно");
        dispatch(props.registerActin());
        return;
      }
      props.set(response.message.errors[0]["msg"]);
    } catch (error) {
      console.log(error);
    }
    dispatch(props.registerActin());
  };
  const reg = () => {
    props.setAdd(!props.add);
    props.set("");
  };
  return (
    <div className={styleButtonBlock.button_container}>
      <p onClick={reg} className={styleButtonBlock.p}>
        {props.add ? "Зарегистрироваться" : "Войти"}
      </p>
      <div>
        {!props.add ? (
          <button
            type="reset"
            onClick={toButton}
            className={styleButtonBlock.button}
          >
            регистрация
          </button>
        ) : (
          <button
            type="reset"
            onClick={toLogin}
            className={styleButtonBlock.button_signIn}
          >
            <div>
              <svg
                width="20"
                height="20"
                fill="currentColor"
                viewBox="0 0 16 16"
              >
                <path d="M6 3.5a.5.5 0 0 1 .5-.5h8a.5.5 0 0 1 .5.5v9a.5.5 0 0 1-.5.5h-8a.5.5 0 0 1-.5-.5v-2a.5.5 0 0 0-1 0v2A1.5 1.5 0 0 0 6.5 14h8a1.5 1.5 0 0 0 1.5-1.5v-9A1.5 1.5 0 0 0 14.5 2h-8A1.5 1.5 0 0 0 5 3.5v2a.5.5 0 0 0 1 0v-2z" />
                <path d="M11.854 8.354a.5.5 0 0 0 0-.708l-3-3a.5.5 0 1 0-.708.708L10.293 7.5H1.5a.5.5 0 0 0 0 1h8.793l-2.147 2.146a.5.5 0 0 0 .708.708l3-3z" />
              </svg>
              <p>войти</p>
            </div>
          </button>
        )}
      </div>
      <p className={styleButtonBlock.error}>{props.get}</p>
    </div>
  );
};

export default ButtonBlock;
